  Object.assign(translations.zh, { "Total guide downloads":"指南下载总数" });  function translateDynamicCatalogueName(source, language) {
    if (language === "ms") {
      source = source.replace(/Explore a mysterious island, solve Year ([2-5]) mathematics puzzles, collect keys, and escape before time runs out\./g, "Terokai pulau misteri, selesaikan teka-teki Matematik Tahun $1, kumpulkan kunci dan lepaskan diri sebelum masa tamat.");
      return source
        .replace(/\bYear ([1-6])\b/g, "Tahun $1")
        .replace(/\bForm ([1-5])\b/g, "Tingkatan $1");
    }
    if (language === "zh") {
      source = source.replace(/Explore a mysterious island, solve Year ([2-5]) mathematics puzzles, collect keys, and escape before time runs out\./g, (_, number) => `探索神秘岛屿，解决${["","一","二","三","四","五"][number]}年级数学谜题，收集钥匙并在时间结束前逃脱。`);
      const numbers = { "1":"一", "2":"二", "3":"三", "4":"四", "5":"五", "6":"六" };
      return source
        .replace(/\bYear ([1-6])\b/g, (_, number) => `${numbers[number]}年级`)
        .replace(/\bForm ([1-5])\b/g, (_, number) => `中${numbers[number]}`);
    }
    return source;
  }
